-- V92: 문서 OCR 템플릿 5종을 '밴드+패턴(kind)' 방식으로 전환(자동차등록증 V88과 동일 강건성).
-- 고정박스는 손정렬 코너 편차에 값이 밀려 오추출 → 넉넉한 밴드 + 값패턴(plate/alnum/name/licno/date_end/year)으로 위치무관 추출.
-- 필드 key·aspect 는 기존과 동일(검증 배선 무영향). paddle document_align.py 에 kind 4종 추가 동반.
-- 실샘플 6개 코너세트 검증: 인력3종 6/6 정답, 건설기계 주요필드 5~6/6(극단코너만 열화), 조종사 면허번호는 저해상 글자오독(수동보정).
UPDATE document_types SET ocr_region_template = '{"version": 1, "aspect": {"w": 1240, "h": 1754}, "fields": [{"key": "license_no", "box": [0.33, 0.19, 0.57, 0.115], "kind": "licno"}, {"key": "name", "box": [0.33, 0.285, 0.39, 0.1], "kind": "name"}, {"key": "expiry_date", "box": [0.36, 0.61, 0.54, 0.16], "kind": "date_end"}]}' WHERE id = 1; -- 운전면허증
UPDATE document_types SET ocr_region_template = '{"version": 1, "aspect": {"w": 1754, "h": 1240}, "fields": [{"key": "registration_no", "box": [0.5, 0.4, 0.4, 0.1], "kind": "licno"}, {"key": "name", "box": [0.45, 0.25, 0.35, 0.1], "kind": "name"}, {"key": "completed_date", "box": [0.35, 0.48, 0.45, 0.1], "kind": "date"}]}' WHERE id = 3; -- 안전교육 이수증
UPDATE document_types SET ocr_region_template = '{"version": 1, "aspect": {"w": 1754, "h": 1240}, "fields": [{"key": "license_no", "box": [0.05, 0.48, 0.63, 0.11], "kind": "licno"}, {"key": "name", "box": [0.2, 0.24, 0.4, 0.12], "kind": "name"}, {"key": "birth_date", "box": [0.05, 0.35, 0.6, 0.13], "kind": "date"}]}' WHERE id = 13; -- 화물운송자격증
